+        let start = crate::tracking::query_timer();
+        let fut = self.inner.query_one(cx, sql, params);
+        async move {
+            let result = fut.await;
+            let elapsed = crate::tracking::elapsed_us(start);
+            crate::tracking::record_query(sql, elapsed);
+            result
+        }
+    }
